API_name: nchu_course_search_by_time
Description:
{
  "description": "Search courses by class time. JSON string containing search results",
  "required_parameters": [
    {
      "name": "weekday",
      "type": "STRING",
      "description": "Day of week (1=Monday, 2=Tuesday, ..., 7=Sunday)"
    }
  ],
  "optional_parameters": [
    {
      "name": "period",
      "type": "STRING",
      "description": "Class period (1-9 for day classes, A-D for evening classes), optional",
      "default": null
    },
    {
      "name": "limit",
      "type": "NUMBER",
      "description": "Maximum number of results to return (default: 20)",
      "default": 20
    },
    {
      "name": "semester",
      "type": "STRING",
      "description": "Semester code. If not specified, uses the latest semester.",
      "default": null
    }
  ]
}

